// =============================================================================
// SPLIT QUERIES - v13
// Splits each client into 3 separate items (one per query)
// =============================================================================

const allClients = $input.all();
const output = [];

for (const clientItem of allClients) {
  const client = clientItem.json;

  for (let qIdx = 0; qIdx < client.searchQueries.length; qIdx++) {
    output.push({
      json: {
        clientName: client.name,
        clientIndustry: client.industry,
        clientCompetitors: client.competitors,
        clientPersonas: client.personas,
        clientSlackChannel: client.slackChannel,
        queryIndex: qIdx,
        searchQuery: client.searchQueries[qIdx]
      }
    });
  }
}

console.log(`Split ${allClients.length} clients into ${output.length} search queries`);
return output;

// =============================================================================
// MERGE & DEDUPE - v13 (STRICT DATE FILTERING)
// Rejects: articles with missing dates OR older than 7 days OR before Jan 2026
// =============================================================================

const allItems = $input.all();
const splitItems = $('Split Queries').all();

const clientResults = {};

for (let i = 0; i < allItems.length; i++) {
  const exaResponse = allItems[i].json;
  const queryMeta = splitItems[i].json;
  const clientName = queryMeta.clientName;

  if (!clientResults[clientName]) {
    clientResults[clientName] = {
      name: clientName,
      industry: queryMeta.clientIndustry,
      competitors: queryMeta.clientCompetitors,
      personas: queryMeta.clientPersonas,
      slackChannel: queryMeta.clientSlackChannel,
      articles: [],
      seenUrls: new Set()
    };
  }

  const results = exaResponse.results || [];

  for (const article of results) {
    const url = article.url || '';

    if (clientResults[clientName].seenUrls.has(url)) {
      continue;
    }

    const pubDate = article.publishedDate ? new Date(article.publishedDate) : null;
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    const jan2026 = new Date('2026-01-01');

    if (!pubDate || isNaN(pubDate.getTime())) {
      console.log(`REJECTED (no valid date): ${clientName} - ${article.title}`);
      continue;
    }

    if (pubDate < sevenDaysAgo || pubDate < jan2026) {
      console.log(`REJECTED (too old: ${article.publishedDate}): ${clientName} - ${article.title}`);
      continue;
    }

    clientResults[clientName].seenUrls.add(url);
    clientResults[clientName].articles.push({
      title: article.title || 'Untitled',
      url: url,
      publishedDate: article.publishedDate.split('T')[0],
      text: article.text ? article.text.substring(0, 1200).trim() : 'No content available'
    });
  }
}

const output = [];

for (const clientName of Object.keys(clientResults)) {
  const client = clientResults[clientName];
  delete client.seenUrls;

  let articlesText = '';
  if (client.articles.length === 0) {
    articlesText = 'NO RELEVANT ARTICLES FOUND THIS WEEK. Write a brief note stating no major ' + 
                   client.industry + ' developments were identified in the past 7 days.';
  } else {
    articlesText = client.articles.map((a, idx) => {
      return `--- Article ${idx + 1} ---\nTitle: ${a.title}\nDate: ${a.publishedDate}\nURL: ${a.url}\nContent: ${a.text}`;
    }).join('\n\n');
  }

  output.push({
    json: {
      name: client.name,
      industry: client.industry,
      competitors: client.competitors,
      personas: client.personas,
      slackChannel: client.slackChannel,
      articlesText: articlesText,
      articleCount: client.articles.length,
      articles: client.articles
    }
  });

  console.log(`${client.name}: ${client.articles.length} articles passed date filter`);
}

return output;

// =============================================================================
// BUILD CLIENT OUTPUT - v13
// Wraps GPT briefing in page HTML, extracts summary for TL;DR
// =============================================================================

const clientData = $('Merge & Dedupe').item.json;
const gptRaw = $input.item.json;

let llmOutput = '';
if (typeof gptRaw === 'string') {
  llmOutput = gptRaw;
} else if (gptRaw.message && gptRaw.message.content) {
  llmOutput = gptRaw.message.content;
} else if (gptRaw.text) {
  llmOutput = gptRaw.text;
} else if (gptRaw.output) {
  llmOutput = gptRaw.output;
} else if (gptRaw.content) {
  llmOutput = gptRaw.content;
} else {
  try {
    llmOutput = gptRaw.choices[0].message.content;
  } catch (e) {
    console.log('Could not extract GPT output:', JSON.stringify(gptRaw).substring(0, 200));
  }
}

if (!llmOutput || llmOutput.length < 50) {
  llmOutput = '<div class="exec-summary"><p><strong>Week in Review:</strong> Briefing generation failed. Please check the GPT node output.</p></div>';
}

let briefingHtml = llmOutput
  .replace(/```html\s*/gi, '')
  .replace(/```\s*/g, '')
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .trim();

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', {
  weekday: 'long',
  month: 'long', 
  day: 'numeric',
  year: 'numeric'
});
const shortDate = now.toISOString().split('T')[0];

const pageHtml = `<div class="client-page">
  <div class="header">
    <div class="header-left">
      <div class="brand">ASTRIS PARTNERS</div>
      <div class="client-name">${clientData.name}</div>
    </div>
    <div class="header-right">
      <div class="date">${dateStr}</div>
      <div class="industry-tag">${clientData.industry}</div>
    </div>
  </div>
  <div class="content">
    ${briefingHtml}
  </div>
  <div class="footer">
    <span>CONFIDENTIAL — INTERNAL USE ONLY</span>
    <span>${dateStr.toUpperCase()}</span>
  </div>
</div>`;

let execMatch = briefingHtml.match(/<div class="exec-summary">[\s\S]*?<p>([\s\S]*?)<\/p>/);
let execText = execMatch ? execMatch[1].replace(/<[^>]+>/g, '').replace(/Week in Review:\s*/i, '').trim() : '';

const headlines = [];
const h3Regex = /<h3>(.*?)<\/h3>/g;
let match;
while ((match = h3Regex.exec(briefingHtml)) !== null) {
  headlines.push(match[1].replace(/<[^>]+>/g, '').trim());
}

return {
  json: {
    clientName: clientData.name,
    industry: clientData.industry,
    slackChannel: clientData.slackChannel,
    pageHtml: pageHtml,
    execText: execText,
    headlines: headlines.slice(0, 5).join(' | '),
    articleCount: clientData.articleCount,
    dateStr: dateStr,
    shortDate: shortDate
  }
};

// =============================================================================
// COMBINE ALL PAGES - v13
// Creates cover page, combines all client pages, builds full HTML with CSS
// =============================================================================

const allBuild = $('Build Client Output').all();
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric', 
  year: 'numeric'
});
const shortDate = now.toISOString().split('T')[0];

const clientList = allBuild.map(it => it.json.clientName);
let coverClients = '';
for (let i = 0; i < clientList.length; i++) {
  coverClients += `<div class="cover-client">
    <span class="cover-num">${String(i + 1).padStart(2, '0')}</span>
    ${clientList[i]}
  </div>`;
}

const coverHtml = `<div class="cover-page">
  <div class="cover-top">
    <div class="cover-brand">ASTRIS PARTNERS</div>
  </div>
  <div class="cover-center">
    <div class="cover-accent"></div>
    <div class="cover-title">Weekly</div>
    <div class="cover-title">Intelligence</div>
    <div class="cover-subtitle">Report</div>
    <div class="cover-accent"></div>
    <div class="cover-date">${dateStr}</div>
  </div>
  <div class="cover-bottom">
    <div class="cover-label">CLIENT BRIEFINGS</div>
    ${coverClients}
  </div>
</div>`;

let allPages = coverHtml;
for (const item of allBuild) {
  allPages += item.json.pageHtml;
}

let tldrInput = '';
for (const item of allBuild) {
  tldrInput += `CLIENT: ${item.json.clientName} (${item.json.industry})\nSUMMARY: ${item.json.execText}\nHEADLINES: ${item.json.headlines}\nARTICLES FOUND: ${item.json.articleCount}\n\n`;
}

const css = `
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap');
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: Inter, Arial, sans-serif; color: #1a1a1a; font-size: 11px; line-height: 1.5; }

/* Cover page */
.cover-page { width: 210mm; height: 297mm; background: #0f172a; padding: 60px 40px; display: flex; flex-direction: column; justify-content: space-between; align-items: center; page-break-after: always; text-align: center; }
.cover-top { width: 100%; }
.cover-brand { color: #64748b; font-size: 11px; letter-spacing: 4px; font-weight: 600; }
.cover-center { display: flex; flex-direction: column; align-items: center; }
.cover-accent { width: 60px; height: 3px; background: #64748b; margin: 20px 0; }
.cover-title { color: #f1f5f9; font-size: 48px; font-weight: 700; line-height: 1.1; }
.cover-subtitle { color: #64748b; font-size: 48px; font-weight: 300; margin-bottom: 8px; }
.cover-date { color: #64748b; font-size: 14px; margin-top: 24px; letter-spacing: 1px; }
.cover-bottom { width: 100%; max-width: 280px; }
.cover-label { color: #64748b; font-size: 9px; letter-spacing: 2px; margin-bottom: 16px; text-transform: uppercase; }
.cover-client { color: #cbd5e1; font-size: 13px; padding: 8px 0; border-bottom: 1px solid #1e293b; text-align: left; }
.cover-client:last-child { border-bottom: none; }
.cover-num { color: #64748b; margin-right: 12px; font-weight: 600; }

/* Client pages */
.client-page { width: 210mm; min-height: 297mm; padding: 24px 32px; page-break-after: always; position: relative; }
.header { border-bottom: 2px solid #1a1a1a; padding-bottom: 8px; margin-bottom: 20px; display: flex; justify-content: space-between; align-items: flex-start; }
.header-left { flex: 1; }
.header-right { text-align: right; display: flex; flex-direction: column; align-items: flex-end; gap: 4px; }
.brand { font-size: 8px; color: #666; letter-spacing: 2px; }
.client-name { font-size: 20px; font-weight: 700; }
.date { font-size: 9px; color: #666; }
.industry-tag { font-size: 8px; background: #eff6ff; color: #1e40af; padding: 2px 8px; border-radius: 3px; display: inline-block; }
.exec-summary { background: #f8fafc; border-left: 3px solid #1e40af; padding: 14px 16px; margin-bottom: 24px; }
.exec-summary p { margin: 0; text-align: justify; line-height: 1.6; }
h2 { font-size: 10px; color: #1e40af; text-transform: uppercase; letter-spacing: 1px; margin: 24px 0 12px; border-bottom: 1px solid #e2e8f0; padding-bottom: 4px; }
h2:first-of-type { margin-top: 0; }
h3 { font-size: 11px; font-weight: 600; margin-bottom: 6px; }
.development { margin-bottom: 16px; padding-left: 16px; border-left: 2px solid #e2e8f0; }
.development p, .content p { margin: 0 0 8px; text-align: justify; line-height: 1.55; }
a { color: #4f46e5; text-decoration: none; }
.footer { position: absolute; bottom: 16px; left: 32px; right: 32px; font-size: 7px; color: #999; display: flex; justify-content: space-between; border-top: 1px solid #eee; padding-top: 8px; }
`;

const fullHtml = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>${css}</style>
</head>
<body>
${allPages}
</body>
</html>`;

return [{
  json: {
    combinedHtml: fullHtml,
    fileName: 'astris-weekly-intelligence-' + shortDate + '.pdf',
    slackChannel: allBuild[0].json.slackChannel,
    tldrInput: tldrInput,
    clientNames: clientList.join(', '),
    dateStr: dateStr,
    shortDate: shortDate
  }
}];

// =============================================================================
// BUILD SLACK MESSAGE - v13
// =============================================================================

const combineData = $('Combine All Pages').item.json;
const tldrRaw = $input.item.json;

let tldr = '';
if (typeof tldrRaw === 'string') {
  tldr = tldrRaw;
} else if (tldrRaw.message && tldrRaw.message.content) {
  tldr = tldrRaw.message.content;
} else if (tldrRaw.text) {
  tldr = tldrRaw.text;
} else if (tldrRaw.output) {
  tldr = tldrRaw.output;
} else if (tldrRaw.content) {
  tldr = tldrRaw.content;
}

if (!tldr) {
  tldr = 'Weekly summary unavailable. Check the workflow for errors.';
}

tldr = tldr.replace(/^([A-Z][A-Z\s&\/\-]+)$/gm, function(match) {
  return '\n*' + match.trim() + '*';
}).trim();

const slackMessage = `:bar_chart:  *Weekly Intelligence Report*  |  _${combineData.dateStr}_\n\n${tldr}\n\n:page_facing_up: _Full PDF report uploading shortly..._`;

return {
  json: {
    slackChannel: combineData.slackChannel,
    slackMessage: slackMessage,
    combinedHtml: combineData.combinedHtml,
    fileName: combineData.fileName,
    dateStr: combineData.dateStr
  }
};

